/**
 * Voxtral TTS configuration interfaces
 *
 * Architecture: 3 components
 * 1. Backbone transformer (Ministral 3B base) — autoregressive text→semantic tokens
 * 2. Flow-matching acoustic transformer — semantic→acoustic latents (16 NFEs)
 * 3. Neural audio codec decoder — acoustic latents→24kHz waveform
 */
interface BackboneConfig {
    dim: number;
    n_layers: number;
    head_dim: number;
    hidden_dim: number;
    n_heads: number;
    n_kv_heads: number;
    vocab_size: number;
    rope_theta: number;
    norm_eps: number;
}
interface FMTransformerConfig {
    input_dim: number;
    dim: number;
    n_layers: number;
    head_dim: number;
    hidden_dim: number;
    n_heads: number;
    n_kv_heads: number;
    nfe: number;
    cfg_alpha: number;
    rope_theta: number;
    sigma: number;
    sigma_max: number;
    n_acoustic_out: number;
    semantic_vocab: number;
}
interface CodecConfig {
    dim: number;
    hidden_dim: number;
    head_dim: number;
    n_heads: number;
    n_kv_heads: number;
    semantic_codebook_size: number;
    semantic_dim: number;
    n_acoustic_codebook: number;
    acoustic_codebook_size: number;
    sampling_rate: number;
    frame_rate: number;
    patch_size: number;
    decoder_stages: number;
    decoder_layers_per_stage: number;
    decoder_conv_strides: number[];
    decoder_conv_kernels: number[];
    attn_sliding_window: number;
    norm_eps: number;
    qk_norm_eps: number;
    qk_norm: boolean;
    layer_scale: boolean;
    weight_norm_conv: boolean;
}
interface VoxtralConfig {
    backbone: BackboneConfig;
    fm: FMTransformerConfig;
    codec: CodecConfig;
}

